INSERT INTO public.pets (id, foundation_id, name, species, breed, age_approx, gender, size, description_story, is_vaccinated, is_sterilized, is_dewormed, good_with_kids, good_with_pets, special_needs, main_photo_url, gallery_urls, status, adopted_at, created_at, updated_at) VALUES
('0f62f6cd-cd45-4c51-8050-5b9776f640e3', 'cf755913-f31e-45e6-8fa1-9f482a19276f', 'Luna', 'dog', 'Mestiza', '2 años', 'female', 'medium', 'Luna fue rescatada cuando era cachorra en las calles del centro de Pasto. Estaba asustada y desnutrida, pero con mucho amor y cuidado se convirtió en una perrita alegre y cariñosa. Le encanta jugar con pelotas, dar paseos largos y recibir caricias en la barriga. Es muy sociable con otros perros y con niños. Busca una familia activa que le dé mucho amor.', true, true, true, true, true, NULL, 'https://images.unsplash.com/photo-1587300003388-59208cc962cb?w=800', ARRAY['https://images.unsplash.com/photo-1587300003388-59208cc962cb?w=800'], 'available', NULL, '2025-11-30 01:32:17.00029+00', '2025-11-30 01:32:17.00029+00'),
('3cbd915b-0115-4304-abd8-9ee029e5c20f', 'cf755913-f31e-45e6-8fa1-9f482a19276f', 'Rocky', 'dog', 'Labrador mix', '3 años', 'male', 'large', 'Rocky es un perro noble y protector. Fue abandonado cuando su anterior familia se mudó. Es muy inteligente, conoce comandos básicos y es excelente guardián. Necesita espacio para correr y jugar. Ideal para casas con patio.', true, true, true, true, true, NULL, 'https://images.unsplash.com/photo-1552053831-71594a27632d?w=800', '{}', 'available', NULL, '2025-11-30 01:32:17.00029+00', '2025-11-30 01:32:17.00029+00'),
('5a128f6a-18fc-44c8-b1bd-a1baadc89736', 'cf755913-f31e-45e6-8fa1-9f482a19276f', 'Toby', 'dog', 'Beagle mix', '1 año', 'male', 'medium', 'Toby es un cachorro curioso y juguetón. Fue encontrado en una caja junto a sus hermanos. Tiene mucha energía y le encanta explorar. Perfecto para familias activas que disfruten de aventuras al aire libre.', true, true, true, true, true, NULL, 'https://images.unsplash.com/photo-1544568100-847a948585b9?w=800', '{}', 'in_process', NULL, '2025-11-30 01:32:17.00029+00', '2025-11-30 01:32:17.00029+00'),
('40646081-0d11-4be5-991b-ecc9e98c9c61', 'cf755913-f31e-45e6-8fa1-9f482a19276f', 'Canela', 'dog', 'Cocker mix', '5 años', 'female', 'medium', 'Canela es una perrita dulce y tranquila. Fue rescatada de una situación de negligencia. Es perfecta para hogares tranquilos, le gusta dormir en cojines suaves y dar caminatas cortas. Muy cariñosa con sus humanos.', true, true, true, true, false, NULL, 'https://images.unsplash.com/photo-1517849845537-4d257902454a?w=800', '{}', 'available', NULL, '2025-11-30 01:32:17.00029+00', '2025-11-30 01:32:17.00029+00'),
('a113d4f6-ecdd-4bdd-9b78-7168ddd97f02', '552a637d-f3d3-4c84-9c14-7f643164b7ea', 'Michi', 'cat', 'Siamés mix', '1 año', 'male', 'small', 'Michi es un gato elegante y cariñoso con hermosos ojos azules. Fue encontrado abandonado en un parque. Es muy vocal y le gusta "conversar" con sus humanos. Perfecto para apartamentos, es muy limpio y tranquilo.', true, true, true, true, true, NULL, 'https://images.unsplash.com/photo-1514888286974-6c03e2ca1dba?w=800', '{}', 'available', NULL, '2025-11-30 01:32:17.00029+00', '2025-11-30 01:32:17.00029+00'),
('b82e3e03-4a93-4e66-b5c6-7c9521f75c5e', '552a637d-f3d3-4c84-9c14-7f643164b7ea', 'Nala', 'cat', 'Mestiza', '6 meses', 'female', 'small', 'Nala es una gatita bebé rescatada junto a su mamá. Es muy juguetona, curiosa y le encanta perseguir juguetes. Está aprendiendo a usar el arenero perfectamente. Busca una familia que la llene de amor y juegos.', true, true, true, true, true, NULL, 'https://images.unsplash.com/photo-1573865526739-10659fec78a5?w=800', '{}', 'available', NULL, '2025-11-30 01:32:17.00029+00', '2025-11-30 01:32:17.00029+00'),
('d986c71e-8dd4-458d-bed3-165caac116ad', '552a637d-f3d3-4c84-9c14-7f643164b7ea', 'Cleo', 'cat', 'Persa mix', '2 años', 'female', 'medium', 'Cleo es una gata hermosa y sofisticada. Fue rescatada de una casa de acumuladores. Es tranquila, elegante y le gusta observar por la ventana. Perfecta para hogares sin niños pequeños donde pueda ser la reina.', true, true, true, false, false, NULL, 'https://images.unsplash.com/photo-1518791841217-8f162f1e1131?w=800', '{}', 'available', NULL, '2025-11-30 01:32:17.00029+00', '2025-11-30 01:32:17.00029+00'),
('c7147faf-ebff-4a07-9469-a9a291d99f85', '552a637d-f3d3-4c84-9c14-7f643164b7ea', 'Mía', 'cat', 'Naranja tabby', '8 meses', 'female', 'small', 'Mía es una gatita naranja llena de amor. Ronronea apenas la acaricias y busca constantemente afecto humano. Es muy sociable y se lleva bien con otros gatos. Le encanta dormir en lugares cálidos y soleados.', true, true, true, true, true, NULL, 'https://images.unsplash.com/photo-1495360010541-f48722b34f7d?w=800', '{}', 'available', NULL, '2025-11-30 01:32:17.00029+00', '2025-11-30 01:32:17.00029+00'),
('0b14c58e-b4a3-4f11-acd2-50ab38152d0b', 'b3a0b67f-caf8-40b3-a439-8cb94350e80d', 'Max', 'dog', 'Pastor Alemán mix', '4 años', 'male', 'large', 'Max es un perro inteligente y leal. Fue rescatado de una finca donde lo tenían encadenado. A pesar de su pasado difícil, es muy noble y cariñoso. Conoce comandos y es muy obediente. Necesita un humano experimentado.', true, true, true, true, false, NULL, 'https://images.unsplash.com/photo-1589941013453-ec89f33b5e95?w=800', '{}', 'available', NULL, '2025-11-30 01:32:17.00029+00', '2025-11-30 01:32:17.00029+00'),
('4a629920-5463-4bd7-8217-802a99366a64', 'b3a0b67f-caf8-40b3-a439-8cb94350e80d', 'Pelusa', 'dog', 'Poodle mix', '7 años', 'female', 'small', 'Pelusa es una perrita senior dulce y tranquila. Fue abandonada cuando su dueña falleció. Es muy adaptable y agradecida. Perfecta para personas mayores o familias que busquen una compañera tranquila y cariñosa.', true, true, true, true, true, 'Requiere dieta especial para seniors', 'https://images.unsplash.com/photo-1591160690555-5debfba289f0?w=800', '{}', 'available', NULL, '2025-11-30 01:32:17.00029+00', '2025-11-30 01:32:17.00029+00'),
('6507673a-c56f-4ecb-9772-7d8024058045', 'b3a0b67f-caf8-40b3-a439-8cb94350e80d', 'Simón', 'cat', 'Negro', '3 años', 'male', 'medium', 'Simón es un gato negro hermoso y misterioso. Fue rescatado de la calle durante una noche de lluvia. Es independiente pero cariñoso cuando quiere. Le encanta explorar y cazar insectos. Rompe el mito de los gatos negros.', true, true, true, true, true, NULL, 'https://images.unsplash.com/photo-1514888286974-6c03e2ca1dba?w=800', '{}', 'available', NULL, '2025-11-30 01:32:17.00029+00', '2025-11-30 01:32:17.00029+00');
INSERT INTO public.adoptions (id, pet_id, adopter_id, foundation_id, status, adopter_message, foundation_notes, rejection_reason, created_at, updated_at, resolved_at) VALUES
('f452a579-df89-4864-a50a-8856150e6eb9', '0f62f6cd-cd45-4c51-8050-5b9776f640e3', '9dc631bb-88b5-4968-b0a0-599f2c0da5d3', 'cf755913-f31e-45e6-8fa1-9f482a19276f', 'pending', 'Hola, me encantaría darle un hogar a Luna. Tengo experiencia con perros y un apartamento grande con terraza. Trabajo desde casa así que tendría mucho tiempo para ella.', NULL, NULL, '2025-11-30 01:32:17.00029+00', '2025-11-30 01:32:17.00029+00', NULL),
('8ba34d77-ff62-4181-a4d4-8fa695089559', '5a128f6a-18fc-44c8-b1bd-a1baadc89736', 'c5a485a7-67ea-49d3-acf5-d4605ff4b840', 'cf755913-f31e-45e6-8fa1-9f482a19276f', 'approved', 'Busco un compañero para mi otro perro. Toby se ve muy juguetón y creo que harían buena pareja.', 'El adoptante pasó todas las verificaciones. Tiene casa con patio y experiencia con perros.', NULL, '2025-11-30 01:32:17.00029+00', '2025-11-30 01:32:17.00029+00', '2025-11-30 01:32:17.00029+00'),
('f52896f7-3b6e-438a-b35d-51fede6a2bd9', 'd986c71e-8dd4-458d-bed3-165caac116ad', 'db9884af-053f-4897-be99-5ee7909282dd', '552a637d-f3d3-4c84-9c14-7f643164b7ea', 'rejected', 'Quiero adoptar a Cleo para mi apartamento.', 'La adoptante tiene niños pequeños. Cleo no es compatible con niños.', 'Cleo necesita un hogar sin niños pequeños para su bienestar. Te recomendamos ver otras mascotas más compatibles.', '2025-11-30 01:32:17.00029+00', '2025-11-30 01:32:17.00029+00', '2025-11-30 01:32:17.00029+00'),
('ddf4fca1-2a6a-421e-85c5-4f3aeae1ace9', 'b82e3e03-4a93-4e66-b5c6-7c9521f75c5e', 'db9884af-053f-4897-be99-5ee7909282dd', '552a637d-f3d3-4c84-9c14-7f643164b7ea', 'pending', 'Después de conocer más sobre Nala, creo que sería perfecta para nuestra familia. Mis hijos ya son más grandes (8 y 10 años) y les encantan los gatos.', NULL, NULL, '2025-11-30 01:32:17.00029+00', '2025-11-30 01:32:17.00029+00', NULL);
